{"file_path":"core/common/test/ReproductionTest.kt","content":"package kotlinx.datetime

import kotlinx.datetime.format.*
import kotlin.test.*

class ReproductionTest {
    @Test
    fun testInstantParseWithMissingSeconds() {
        // This is documented as NOT allowed, but JVM allows it.
        // On iOS/Native it fails.
        val input = "2024-03-19T17:50Z"
        try {
            Instant.parse(input)
            // If it succeeds, it's currently behaving like JVM
        } catch (e: DateTimeFormatException) {
            // If it fails, it's behaving like Native
        }
    }

    @Test
    fun testInstantParseWithMissingOffsetMinutes() {
        // This is documented as ALLOWED, but fails on both.
        val input = "2024-03-19T17:50:00+03"
        try {
            Instant.parse(input)
        } catch (e: DateTimeFormatException) {
            fail("Should allow missing offset minutes: $e")
        }
    }

    @Test
    fun testIsoDateTimeOffsetDirectly() {
        val input = "2024-03-19T17:50:00+03"
        DateTimeComponents.Formats.ISO_DATE_TIME_OFFSET.parse(input)
    }
}
"}

