 14→@Serializable(with = UtcOffsetSerializer::class)
 15→public actual class UtcOffset private constructor(public actual val totalSeconds: Int) {
 16→
 17→    override fun hashCode(): Int = totalSeconds
 18→    actual override fun equals(other: Any?): Boolean = other is UtcOffset && this.totalSeconds == other.totalSeconds
